import os
import hashlib
from cryptography.fernet import Fernet

def encrypt_credit_card(number):
    # Use a fast encryption method like AES-GCM to encrypt the number
    key = Fernet.generate_key()
    f = Fernet(key)
    encrypted_number = f.encrypt(str(number).encode())
    return encrypted_number.decode()

def decrypt_credit_card(encrypted_number):
    # Use the same encryption key to decrypt the number
    f = Fernet(os.environ['ENCRYPTION_KEY'])
    decrypted_number = f.decrypt(str(encrypted_number).encode())
    return int(decrypted_number)